package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.exception.MessageException;
import com.google.common.base.Predicate;
import com.google.common.collect.Iterables;
import com.google.common.collect.SortedSetMultimap;
import lombok.NonNull;
import org.apache.commons.lang.builder.EqualsBuilder;
import org.joda.time.LocalDate;

import java.util.Collection;
import java.util.Collections;
import java.util.SortedSet;

public class LoonElementManagerImp implements LoonElementManager {

    private final SortedSet<LoonElement> persoonsElementen = LoonElement.createSortedSet();
    private final SortedSetMultimap<Opdracht, LoonElement> opdrachtsElementenMap = LoonElement.createSortedSetMultiMap();
    private final SortedSetMultimap<Opper, LoonElement> opperElementenMap = LoonElement.createSortedSetMultiMap();

    @Override
    public Collection<LoonElement> getPersoonsElementen() {
        return Collections.unmodifiableSortedSet(persoonsElementen);
    }

    @Override
    public Collection<LoonElement> getOpdrachtsElementen(Opdracht opdracht) {
        return Collections.unmodifiableSortedSet(opdrachtsElementenMap.get(opdracht));
    }

    @Override
    public Collection<LoonElement> getOpdrachtsElementen(Collection<Opdracht> opdrachten) {
        SortedSet<LoonElement> opdrachtsElementen = LoonElement.createSortedSet();
        for (Opdracht opdracht : opdrachten) {
            opdrachtsElementen.addAll(opdrachtsElementenMap.get(opdracht));
        }
        return Collections.unmodifiableSortedSet(opdrachtsElementen);
    }

    @Override
    public Collection<LoonElement> getOpperElementen(Opper opper) {
        return Collections.unmodifiableSortedSet(opperElementenMap.get(opper));
    }

    @Override
    public Collection<LoonElement> getOpperElementen(Collection<Opper> oppers) {
        SortedSet<LoonElement> oppersElementen = LoonElement.createSortedSet();
        for (Opper opper : oppers) {
            oppersElementen.addAll(opperElementenMap.get(opper));
        }
        return Collections.unmodifiableSortedSet(oppersElementen);
    }

    @Override
    public void addLoonElement(LoonElement loonElement, Opper opper) {
        loonElement.setOpper(opper);
        SortedSet<LoonElement> opperElementen = opperElementenMap.get(opper);
        LoonElement found = Iterables.find(opperElementen, new BevatLoonElementPredicate(loonElement), null);
        if (found == null) {
            persoonsElementen.add(loonElement);
            opdrachtsElementenMap.put(opper.getOpdracht(), loonElement);
            opperElementenMap.put(opper, loonElement);
        } else {
            throw new MessageException(
                    "Kan loonelement niet toevoegen,de combinatie aardKodeExtensie, opper, beslagdatum en referentieJaar moet uniek zijn. " + loonElement
                            .toStringBasic());
        }
    }

    @Override
    public LoonElement getOrCreateLoonElement(Opper opper, AardKodeExtensie defaultLoonCode) {
        LoonElement element = getLoonElement(defaultLoonCode, opper, null);
        if (element == null) {
            element = new LoonElement(defaultLoonCode);
            addLoonElement(element, opper);
        }
        return element;
    }

    private static final class BevatLoonElementPredicate implements Predicate<LoonElement> {

        private final Opper opper;
        private final AardKodeExtensie aardKodeExtensie;
        private final LocalDate beslagDatum;
        private final Integer referentieJaar;

        public BevatLoonElementPredicate(AardKodeExtensie aardKodeExtensie, Opper opper, LocalDate beslagDatum, Integer referentieJaar) {
            this.opper = opper;
            this.aardKodeExtensie = aardKodeExtensie;
            this.beslagDatum = beslagDatum;
            this.referentieJaar = referentieJaar;
        }

        public BevatLoonElementPredicate(LoonElement element) {
            this(element.getAardKodeExtensie(), element.getOpper(), element.getBeslagDatum(), element.getReferentieJaar());
        }

        @Override
        public boolean apply(@NonNull LoonElement element) {
            return new EqualsBuilder().append(this.aardKodeExtensie, element.getAardKodeExtensie()).append(this.opper, element.getOpper())
                    .append(this.beslagDatum, element.getBeslagDatum()).append(this.referentieJaar, element.getReferentieJaar()).isEquals();
        }
    }

    @Override
    public LoonElement getLoonElement(AardKodeExtensie looncode, Opper opper, LocalDate beslagDatum, Integer referentieJaar) {
        Collection<LoonElement> opperElementen = opperElementenMap.get(opper);
        return Iterables.find(opperElementen, new BevatLoonElementPredicate(looncode, opper, beslagDatum, referentieJaar), null);
    }

    @Override
    public LoonElement getLoonElement(AardKodeExtensie looncode, Opper opper, Integer referentieJaar) {
        return getLoonElement(looncode, opper, null, referentieJaar);
    }

}
